function parkingFee(
  minutesParked: number,
  isWeekend: boolean,
  isElectricVehicle: boolean,
  isLostTicket: boolean
): number {
  if (isLostTicket) {
    return 45.0;
  }

  let baseFee = 0;
  if (minutesParked > 15) {
    const hours = Math.ceil((minutesParked - 15) / 60);
    baseFee = hours * 3.5;
  }

  let discountedFee = baseFee;
  if (isElectricVehicle) {
    discountedFee = baseFee * 0.8;
    discountedFee = Math.round(discountedFee * 4) / 4;
  }

  const cap = isWeekend ? 18.0 : 24.0;
  const finalFee = Math.min(discountedFee, cap);

  return Math.round(finalFee * 100) / 100;
}

import { DateTime } from "luxon";

interface ParkingInput {
  durationMinutes: number;
  vehicleType: "normal" | "electric";
  isWeekend: boolean;
  lostTicket: boolean;
}

function calculateParkingFee(input: ParkingInput): number {
  const { durationMinutes, vehicleType, isWeekend, lostTicket } = input;

  if (lostTicket) {
    return 45.0;
  }

  if (durationMinutes <= 0) {
    return 0.0;
  }

  const freeMinutes = 15;
  const chargeableMinutes = Math.max(0, durationMinutes - freeMinutes);
  const chargeableHours = Math.ceil(chargeableMinutes / 60);
  let baseFee = chargeableHours * 3.5;

  if (vehicleType === "electric") {
    baseFee = baseFee * 0.8;
    baseFee = Math.round(baseFee * 4) / 4;
  }

  const cap = isWeekend ? 18 : 24;
  let finalFee = Math.min(baseFee, cap);

  finalFee = Math.round(finalFee * 100) / 100;

  return finalFee;
}

const testCases: ParkingInput[] = [
  { durationMinutes: 0, vehicleType: "normal", isWeekend: false, lostTicket: false },
  { durationMinutes: 15, vehicleType: "normal", isWeekend: false, lostTicket: false },
  { durationMinutes: 30, vehicleType: "normal", isWeekend: false, lostTicket: false },
