  { durationMinutes: 120, vehicleType: "normal", isWeekend: true, lostTicket: false },
  { durationMinutes: 60, vehicleType: "normal", isWeekend: false, lostTicket: true },
];

testCases.forEach((testCase) => {
  const fee = calculateParkingFee(testCase);
