export interface ParkingParams {
  durationMinutes: number;
  vehicleType: "standard" | "electric";
  dayOfWeek: "weekday" | "weekend";
  lostTicket: boolean;
}

export function calculateParkingFee(params: ParkingParams): number {
  if (params.lostTicket) {
    return 45.0;
  }

  if (params.durationMinutes <= 15) {
    return 0.0;
  }

  const billableMinutes = params.durationMinutes - 15;
  const hoursRoundedUp = Math.ceil(billableMinutes / 60);
  let fee = hoursRoundedUp * 3.5;

  if (params.vehicleType === "electric") {
    fee = fee * 0.8;
    fee = Math.round(fee * 4) / 4;
  }

  const dailyCap = params.dayOfWeek === "weekend" ? 18.0 : 24.0;
  fee = Math.min(fee, dailyCap);

  return Math.round(fee * 100) / 100;
}

