import { describe, it, expect } from 'vitest';

type Vehicle = 'regular' | 'ev';
type DayType = 'weekday' | 'weekend';

interface ParkingInput {
  minutesParked: number;
  vehicle: Vehicle;
  dayType: DayType;
  lostTicket: boolean;
}

function roundToNearestQuarter(amount: number): number {
  return Math.round(amount * 4) / 4;
}

function calculateFee(input: ParkingInput): number {
  if (input.lostTicket) return 45;
  if (input.minutesParked <= 15) return 0;

  const billableMinutes = input.minutesParked - 15;
  const billableHours = Math.ceil(billableMinutes / 60);
  let fee = billableHours * 3.5;

  if (input.vehicle === 'ev') {
    fee = roundToNearestQuarter(fee * 0.8);
  }

  const dailyCap = input.dayType === 'weekday' ? 24 : 18;
  return Math.min(fee, dailyCap);
}

describe('Parking Garage Fee Calculator', () => {
  it('free for 0 minutes', () => {
    expect(calculateFee({ minutesParked: 0, vehicle: 'regular', dayType: 'weekday', lostTicket: false })).toBe(0);
  });

  it('free for exactly 15 minutes', () => {
    expect(calculateFee({ minutesParked: 15, vehicle: 'regular', dayType: 'weekday', lostTicket: false })).toBe(0);
  });

  it('charges $3.50 for 16-60 minutes', () => {
    expect(calculateFee({ minutesParked: 30, vehicle: 'regular', dayType: 'weekday', lostTicket: false })).toBe(3.5);
  });

  it('rounds up to next hour: 61 minutes = $7.00', () => {
    expect(calculateFee({ minutesParked: 76, vehicle: 'regular', dayType: 'weekday', lostTicket: false })).toBe(7);
  });

  it('applies 20% EV discount rounded to nearest quarter', () => {
    expect(calculateFee({ minutesParked: 76, vehicle: 'ev', dayType: 'weekday', lostTicket: false })).toBe(5.75);
  });

  it('enforces weekday cap of $24', () => {
    expect(calculateFee({ minutesParked: 480, vehicle: 'regular', dayType: 'weekday', lostTicket: false })).toBe(24);
  });

  it('enforces weekend cap of $18', () => {
    expect(calculateFee({ minutesParked: 480, vehicle: 'regular', dayType: 'weekend', lostTicket: false })).toBe(18);
  });

  it('flat $45 for lost ticket (no discount/cap)', () => {
    expect(calculateFee({ minutesParked: 30, vehicle: 'ev', dayType: 'weekday', lostTicket: true })).toBe(45);
  });

  it('EV at weekend cap: 2 hours = $5.60, under $18', () => {
    expect(calculateFee({ minutesParked: 135, vehicle: 'ev', dayType: 'weekend', lostTicket: false })).toBe(5.6);
  });
});
